        color rgb_prime;

        if (h >= 0 && h < 60) {
            rgb_prime = color(c, x, 0);
        } else if (h >= 60 && h < 120) {
            rgb_prime = color(x, c, 0);
        } else if (h >= 120 && h < 180) {
